import{j as a,b as t,c as l,a2 as r}from"./chunks/framework.BDRKwY9B.js";const u=JSON.parse('{"title":"认知节点开发","description":"认知节点插件的开发指南（占位）。","frontmatter":{"title":"认知节点开发","description":"认知节点插件的开发指南（占位）。","order":1},"headers":[],"relativePath":"develop/brain-node-development.md","filePath":"develop/brain-node-development.md","lastUpdated":1778837174000}'),o={name:"develop/brain-node-development.md"};function i(n,e,d,p,s,h){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="认知节点开发" tabindex="-1">认知节点开发 <a class="header-anchor" href="#认知节点开发" aria-label="Permalink to &quot;认知节点开发&quot;">​</a></h1><blockquote><p>🚧 认知节点插件体系尚未开放。此页面为规划占位，将在后续版本中补充完整开发指南。</p></blockquote><h2 id="设计方向" tabindex="-1">设计方向 <a class="header-anchor" href="#设计方向" aria-label="Permalink to &quot;设计方向&quot;">​</a></h2><p>认知节点（Brain Node）是 AuroraBot 认知能力的可插拔扩展单元。每个节点可以是：</p><ul><li><strong>Agent 节点</strong> — 执行特定认知任务（如意图识别、记忆检索、自我评估）</li><li><strong>Router 节点</strong> — 决定事件或状态在节点间的流转方向</li></ul><p>节点之间通过有向边连接，构成有向有环图。节点之间通过文件篮机制传递状态——每个节点只看着自己面前的文件篮，一旦有新文件滑入就开始工作。</p><h2 id="预期能力" tabindex="-1">预期能力 <a class="header-anchor" href="#预期能力" aria-label="Permalink to &quot;预期能力&quot;">​</a></h2><ul><li>第三方可通过标准接口开发认知节点插件</li><li>节点可声明自己的输入/输出契约</li><li>内核调度器自动管理节点的生命周期和调度优先级</li><li>节点可访问统一 LLM 网关和统一联合记忆</li></ul><h2 id="继续阅读" tabindex="-1">继续阅读 <a class="header-anchor" href="#继续阅读" aria-label="Permalink to &quot;继续阅读&quot;">​</a></h2><ul><li>想理解认知架构：读 <a href="./../architecture/brain-architecture.html">认知架构</a></li><li>想理解节点设计哲学：读 <a href="./../architecture/node-system.html">节点系统</a></li><li>想开发 App 插件：读 <a href="./app-development.html">App 开发指南</a></li></ul>',10)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
